// src/data/cities-data.ts
// ─────────────────────────────────────────────────────────────────────────────
// CENTRALIZED CITY DATA — PROXEN DIGITAL AGENCY
//
// Architecture overview:
//   • Every city is a fully self-contained CityData object.
//   • No templates, no placeholder replacements — every field is final,
//     unique copy written specifically for that city.
//   • Components read from this file; no WordPress REST calls are made for
//     city content anymore.
//   • The `slug` drives routing: /cities/:slug  → looks up by slug here.
//   • `serviceType` drives the listing page grouping (same key as before).
// ─────────────────────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────────────
// TYPE DEFINITIONS
// ─────────────────────────────────────────────────────────────────────────────

export interface CityServicePill { label: string; href?: string; }
export interface CityRelatedServiceCard { title: string; description: string; href: string; }
export interface CityFaqItem { question: string; answer: string; }
export interface CityHero { eyebrow: string; heading: { main: string; highlight?: string; }; description: string; primaryCta: { label: string; href: string }; secondaryCta?: { label: string; href: string }; image: { src: string; alt: string; }; badge?: { value: string; label: string; }; }
export interface CityIntro { eyebrow: string; heading: string; description: string; pills: CityServicePill[]; primaryCta: { label: string; href: string }; secondaryCta?: { label: string; href: string }; relatedServicesPanel: { heading: string; services: CityRelatedServiceCard[]; }; }
export interface CityFaqSection { heading: string; headingHighlight?: string; faqs: CityFaqItem[]; }
export interface CityAboutSection { eyebrow: string; heading: { prefix: string; highlight: string; suffix: string; }; body: string; cta: { label: string; href: string }; image: { src: string; alt: string; }; }
export interface CitySeo { title: string; description: string; canonicalPath: string; }
export interface CityData { slug: string; serviceType: string; cityName: string; state?: string; hero: CityHero; intro: CityIntro; faq: CityFaqSection; about: CityAboutSection; seo: CitySeo; }

// ─────────────────────────────────────────────────────────────────────────────
// SERVICE DISPLAY MAP
// ─────────────────────────────────────────────────────────────────────────────
export const SERVICE_DISPLAY_NAMES: Record<string, string> = {
  'branding-identity-design-company': 'Branding & Design',
  'web-design-services': 'Website Design',
  'web-development': 'Web Development',
  'seo': 'SEO',
  'ecommerce-store-development-company': 'E-Commerce Solutions',
  'digital-marketing': 'Digital Marketing',
  'social-media-management': 'Social Media Management',
  'mobile-app-development': 'Mobile App Development'
};

export const getServiceDisplayName = (key: string): string =>
  SERVICE_DISPLAY_NAMES[key] ??
  key
    .replace(/[-_]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/\b\w/g, (c) => c.toUpperCase());

