export const getCityBySlug = (slug: string): CityData | undefined => citiesData.find((city) => city.slug === slug);
export const getCitiesByServiceType = (serviceType: string): CityData[] => citiesData.filter((city) => city.serviceType === serviceType);
export const getAllServiceTypeKeys = (): string[] => {
  const keys = [...new Set(citiesData.map((c) => c.serviceType))];
  return keys.sort((a, b) => getServiceDisplayName(a).localeCompare(getServiceDisplayName(b)));
};
export const getAllCitySlugs = (): string[] => citiesData.map((city) => city.slug);